import { test } from 'node:test';
import assert from 'node:assert';
import { ms, parse, format } from './index.ts';

test('ms parses human time strings to milliseconds', () => {
  assert.strictEqual(ms('2 days'), 172800000);
  assert.strictEqual(ms('1h'), 3600000);
  assert.strictEqual(ms('100'), 100);
});

test('ms formats milliseconds to short and long human strings', () => {
  assert.strictEqual(ms(60000), '1m');
  assert.strictEqual(ms(60000, { long: true }), '1 minute');
  assert.strictEqual(ms(2 * 60000, { long: true }), '2 minutes');
});

test('parse rejects strings longer than 100 characters (boundary enforcement)', () => {
  // A purely numeric string of length 101 - well beyond the intended max length of 100.
  const tooLong = '1'.repeat(101);
  assert.throws(
    () => parse(tooLong),
    /must be a string with length between 1 and 99/,
  );
});

test('parse accepts a numeric string right at the 100 character boundary', () => {
  const atLimit = '1'.repeat(100);
  // Should not throw for a string exactly at the allowed max length.
  assert.strictEqual(typeof parse(atLimit), 'number');
});

test('format throws for non-finite numbers', () => {
  assert.throws(() => format(NaN));
  assert.throws(() => format(Infinity));
});
